const cfg = {};
$input.all().forEach(r => { cfg[r.json.key] = r.json.value; });

const hoursBack = parseInt(cfg.fetch_hours_back || '1');
const limit     = parseInt(cfg.fetch_limit || '80');

// Полный ISO timestamp — сервер ходит ВПЕРЁД от since к now
const since = new Date(Date.now() - hoursBack * 3600 * 1000).toISOString();

return [{ json: { limit, since, hoursBack } }];

const cfg      = $('Parse Config').first().json;
const channels = $input.all();

const SKIP_IDS = new Set([
  '1111111111', '2222222222'
]);

const seen = new Set();
return channels
  .filter(ch => {
    const id = String(ch.json.id);
    if (SKIP_IDS.has(id) || seen.has(id)) return false;
    seen.add(id);
    return true;
  })
  .map(ch => ({
    json: { ...ch.json, limit: cfg.limit, since: cfg.since }
  }));

// Матчим по channel_id из ответа API
const splitChannels = $('Split Per Channel').all();

const channelMap = {};
splitChannels.forEach(ch => {
  const id = String(ch.json.id || '');
  channelMap[id] = ch.json;
});

const result = [];
const fetchedItems = $input.all();

for (let i = 0; i < fetchedItems.length; i++) {
  const item = fetchedItems[i];

  const rawChannel = item.json.channel;
  const channelId  = rawChannel ? String(rawChannel) : '';

  const ch = channelMap[channelId] || {};
  const channelTitle = ch.title || ch.username || channelId;

  const messages = Array.isArray(item.json.messages) ? item.json.messages : [];

  for (const m of messages) {
    if (!m.text || m.text.trim().length <= 30) continue;
    result.push({
      json: {
        msg_id:        String(m.id),
        channel_id:    channelId,
        channel_title: channelTitle,
        text:          m.text.trim(),
        msg_date:      new Date(m.date * 1000).toISOString(),
        embed_input:   `[${channelTitle}] ${m.text.trim()}`
      }
    });
  }
}

if (result.length === 0) {
  return [{ json: { skip: true } }];
}

return result;

// Собираем все сообщения в один item с массивом и готовим VALUES для дедуп-запроса
const messages = $input.all().filter(m => !m.json.skip && m.json.embed_input);

if (messages.length === 0) {
  // Нечего обрабатывать — останавливаем цепочку (downstream не запускается)
  return [];
}

const esc = (s) => String(s).replace(/'/g, "''");

const valuesClause = messages
  .map(m => `('${esc(m.json.msg_id)}','${esc(m.json.channel_id)}')`)
  .join(',');

return [{
  json: {
    messages: messages.map(m => m.json),
    valuesClause,
    incomingCount: messages.length
  }
}];

