// Отфильтровываем сообщения, которые уже есть в БД — экономим OpenAI
const aggregated = $('Aggregate for Dedup').first().json;
const allMessages = aggregated.messages || [];

const existingRows = $input.all().filter(r => r.json && r.json.msg_id);
const existing = new Set(
  existingRows.map(r => `${r.json.msg_id}:${r.json.channel_id}`)
);

const fresh = allMessages.filter(m =>
  !existing.has(`${m.msg_id}:${m.channel_id}`)
);

console.log(`[Dedup] incoming=${allMessages.length} existing=${existing.size} fresh=${fresh.length}`);

if (fresh.length === 0) {
  // Все уже в БД — останавливаем цепочку, эмбеддинги делать не нужно
  return [];
}

return fresh.map(m => ({ json: m }));

const messages = $input.all().filter(m => !m.json.skip && m.json.embed_input);

if (messages.length === 0) {
  return [];
}

const CHUNK_SIZE = 100;
const result = [];

for (let i = 0; i < messages.length; i += CHUNK_SIZE) {
  const chunk = messages.slice(i, i + CHUNK_SIZE);
  result.push({
    json: {
      inputs:   chunk.map(m => m.json.embed_input),
      messages: chunk.map(m => m.json)
    }
  });
}

return result;

// Сшиваем эмбеддинги с сообщениями ПОИНДЕКСНО.
// HTTP Request «Batch Embeddings Request» отдаёт N items (по одному на чанк),
// в том же порядке, что приходили из Collect Inputs.
// Поэтому items[idx] соответствует $('Collect Inputs').all()[idx].

const responses = $input.all();
const chunks    = $('Collect Inputs').all();
const result    = [];

for (let idx = 0; idx < responses.length; idx++) {
  const response = responses[idx].json;

  if (response.error) {
    throw new Error('OpenAI error in chunk ' + idx + ': ' + JSON.stringify(response.error));
  }

  const embData = response.data;
  if (!embData || !Array.isArray(embData)) {
    throw new Error('Нет data в чанке ' + idx + ': ' + JSON.stringify(response).slice(0, 300));
  }

  const chunk = chunks[idx];
  if (!chunk) throw new Error('Не найден соответствующий chunk для idx=' + idx);

  const messages = chunk.json.messages;
  if (!Array.isArray(messages)) throw new Error('messages не массив в chunk ' + idx);

  // Сортируем по index — на всякий случай, чтобы порядок совпал с messages[]
  const sorted = [...embData].sort((a, b) => a.index - b.index);

  for (let i = 0; i < sorted.length; i++) {
    const emb = sorted[i];
    const msg = messages[i];
    if (!msg) throw new Error(`Нет сообщения для chunk=${idx} idx=${i}`);

    const embRaw = emb.embedding;
    const vector = Array.isArray(embRaw)
      ? embRaw
      : Object.keys(embRaw)
          .sort((a, b) => Number(a) - Number(b))
          .map(k => embRaw[k]);

    if (!vector.length) throw new Error(`Пустой вектор: chunk=${idx} idx=${i}`);

    result.push({
      json: {
        msg_id:        String(msg.msg_id || ''),
        channel_id:    String(msg.channel_id || ''),
        channel_title: String(msg.channel_title || ''),
        text:          String(msg.text || ''),
        msg_date:      String(msg.msg_date || ''),
        embedding:     '[' + vector.join(',') + ']'
      }
    });
  }
}

console.log(`[Merge] chunks=${responses.length} total_messages=${result.length}`);
return result;

const r = $input.first().json;
console.log(`[Cleanup] Удалено: ${r.deleted_count} | retention: ${r.retention_days} дней | cutoff: ${r.cutoff_date}`);
return [{ json: r }];

const items = $input.all();

const vars = {};

for (const item of items) {
  const row = item.json;

  const cleanRow = {};
  for (const key of Object.keys(row)) {
    cleanRow[key.trim()] = row[key];
  }

  const name = cleanRow.name;
  const value = cleanRow.value;

  if (name) {
    vars[name] = value;
  }
}

return [
  {
    json: {
      vars
    }
  }
];
